1471					ast_invariant(conv, to.isBitstreamType());
1472	
1473					// evaluate the bitstream
1474					auto &stream_expr = conv.operand().as<ast::StreamingConcatenationExpression>();
1475					RTLIL::SigSpec stream = streaming(stream_expr);
1476	
1477					// pad to fit target size
1478					ast_invariant(conv, stream.size() <= (int) expr.type->getBitstreamWidth());
1479					ret = {stream, RTLIL::SigSpec(RTLIL::S0, expr.type->getBitstreamWidth() - stream.size())};
1480				}
1481			}
1482			break;
1483		case ast::ExpressionKind::IntegerLiteral:
1484			{
1485				const ast::IntegerLiteral &lit = expr.as<ast::IntegerLiteral>();
1486				ret = convert_svint(lit.getValue());
1487			}
1488			break;
1489		case ast::ExpressionKind::RangeSelect:
1490			{
1491				const ast::RangeSelectExpression &sel = expr.as<ast::RangeSelectExpression>();
1492				AddressingResolver addr(*this, sel);
1493				ret = addr.shift_down((*this)(sel.value()), sel.type->getBitstreamWidth());
1494			}
1495			break;
1496		case ast::ExpressionKind::ElementSelect:
1497			{
1498				const ast::ElementSelectExpression &elemsel = expr.as<ast::ElementSelectExpression>();
1499	
1500				if (netlist.is_inferred_memory(elemsel.value()) && !in_sva_expression) {
1501					int width = elemsel.type->getBitstreamWidth();
1502					std::string id = netlist.id(elemsel.value()
1503											.as<ast::ValueExpressionBase>().symbol);
1504					RTLIL::Cell *memrd = netlist.canvas->addCell(netlist.new_id(), ID($memrd_v2));
1505					memrd->setParam(ID::MEMID, id);
1506					memrd->setParam(ID::CLK_ENABLE, false);
1507					memrd->setParam(ID::CLK_POLARITY, false);
1508					memrd->setParam(ID::TRANSPARENCY_MASK, RTLIL::Const(0, 0));
1509					memrd->setParam(ID::COLLISION_X_MASK, RTLIL::Const(0, 0));
1510					memrd->setParam(ID::CE_OVER_SRST, false);
1511					memrd->setParam(ID::ARST_VALUE, RTLIL::Const(RTLIL::Sx, width));
1512					memrd->setParam(ID::SRST_VALUE, RTLIL::Const(RTLIL::Sx, width));
1513					memrd->setParam(ID::INIT_VALUE, RTLIL::Const(RTLIL::Sx, width));
1514					memrd->setPort(ID::CLK, RTLIL::Sx);
1515					memrd->setPort(ID::EN, RTLIL::S1);
1516					memrd->setPort(ID::ARST, RTLIL::S0);
1517					memrd->setPort(ID::SRST, RTLIL::S0);
1518					// TODO: signedness
1519					RTLIL::SigSpec addr = (*this)(elemsel.selector());
1520					memrd->setPort(ID::ADDR, addr);
1521					memrd->setParam(ID::ABITS, addr.size());
1522					ret = netlist.add_placeholder_signal(width);
1523					memrd->setPort(ID::DATA, ret);
1524					memrd->setParam(ID::WIDTH, width);
1525					transfer_attrs(netlist, expr, memrd);
1526					break;
1527				}
1528	
1529				AddressingResolver addr(*this, elemsel);
1530				ret = addr.mux((*this)(elemsel.value()), elemsel.type->getBitstreamWidth());
1531			}
1532			break;
1533		case ast::ExpressionKind::Concatenation:
1534			{
1535				const ast::ConcatenationExpression &concat = expr.as<ast::ConcatenationExpression>();
1536				auto operands = concat.operands();
1537				std::vector<RTLIL::SigSpec> parts;
1538				parts.reserve(operands.size());
1539				for (auto op : operands)
1540					parts.push_back((*this)(*op));
1541				// SigSpec appends LSB-first; operands are evaluated in source order
1542				// above and appended in reverse to preserve concatenation order.
1543				for (auto part_it = parts.rbegin(); part_it != parts.rend(); ++part_it)
1544					ret.append(*part_it);
1545			}
1546			break;
1547		case ast::ExpressionKind::SimpleAssignmentPattern:
1548		case ast::ExpressionKind::StructuredAssignmentPattern:
1549			{
1550				repl_count = 1;
1551	
1552				if (0) {
1553		case ast::ExpressionKind::ReplicatedAssignmentPattern:
1554					repl_count = *expr.as<ast::ReplicatedAssignmentPatternExpression>()
1555									.count().eval(const_).integer().as<size_t>();
1556				}
1557	
1558				auto &pattern_expr = static_cast<const ast::AssignmentPatternExpressionBase&>(expr);
1559				auto elements = pattern_expr.elements();
1560	
1561				ret = {};
1562				std::vector<RTLIL::SigSpec> parts;
1563				parts.reserve(elements.size());
1564				for (auto elem : elements)
1565					parts.push_back((*this)(*elem));
1566				// Assignment patterns use the same bit ordering as concatenations.
1567				for (auto part_it = parts.rbegin(); part_it != parts.rend(); ++part_it)
1568					ret.append(*part_it);
1569				ret = ret.repeat(repl_count);
1570			}
1571			break;
1572		case ast::ExpressionKind::ConditionalOp:
1573			{
1574				const auto &ternary = expr.as<ast::ConditionalExpression>();
1575	
1576				require(expr, ternary.conditions.size() == 1);
1577				require(expr, !ternary.conditions[0].pattern);
1578	
1579				ret = netlist.Mux(
1580					(*this)(ternary.right()),
1581					(*this)(ternary.left()),
1582					netlist.ReduceBool((*this)(*(ternary.conditions[0].expr)))
1583				);
1584			}
1585			break;
1586		case ast::ExpressionKind::Replication:
1587			{
1588				const auto &repl = expr.as<ast::ReplicationExpression>();
1589				auto count = repl.count().eval(const_);
1590				ast_invariant(expr, count.isInteger());
1591				int reps = count.integer().as<int>().value(); // TODO: checking int cast
1592				RTLIL::SigSpec concat = (*this)(repl.concat());
1593				for (int i = 0; i < reps; i++)
1594					ret.append(concat);
1595			}
1596			break;
1597		case ast::ExpressionKind::MemberAccess:
1598			{
1599				const auto &acc = expr.as<ast::MemberAccessExpression>();
1600				ret = extract_struct_field((*this)(acc.value()), acc);
1601			}
1602			break;
1603		case ast::ExpressionKind::Call:
1604			{
1605				const auto &call = expr.as<ast::CallExpression>();
1606				if (call.isSystemCall() && (call.getSubroutineName() == "$display"
1607						|| call.getSubroutineName() == "$write")) {
1608					require(expr, procedural != nullptr);
1609					handle_display(*procedural, call);
1610				} else if (call.isSystemCall()) {
1611					auto name = call.getSubroutineName();
1612					if (name == "$countones") {
1613						require(expr, call.arguments().size() == 1);
1614						auto arg = call.arguments()[0];
1615						auto sig = (*this)(*arg);
1616						ret = netlist.CountOnes(sig, (int)call.type->getBitstreamWidth());
1617					} else if (name == "$clog2") {
1618						ast_invariant(expr, call.arguments().size() == 1);
1619						auto arg = call.arguments()[0];
1620						auto sig = (*this)(*arg);
1621						ret = netlist.Clog2(sig, (int)call.type->getBitstreamWidth());
1622					} else if (name == "$past") {
1623						ret = handle_past(*this, call);
1624					} else if (name == "$signed" || name == "$unsigned") {
1625						require(expr, call.arguments().size() == 1);
1626						ret = (*this)(*call.arguments()[0]);
1627					} else if (name == "$readmemb" || name == "$readmemh") {
1628						require(expr, !(call.arguments().size() < 2 || call.arguments().size() > 4));
1629						handle_readmem(*procedural, call);
1630					} else {
1631						auto &d = netlist.add_diag(diag::UnsupportedSystemTask, expr.sourceRange);
1632						d << name;
1633						if (procedural && procedural->timing.kind == ProcessTiming::Initial)
1634							d.addNote(diag::NoteIgnoreInitial, expr.sourceRange.start());
1635						goto error;
1636					}
1637				} else {
1638					const auto &subr = *std::get<0>(call.subroutine);
1639					if (procedural) {
1640						ret = StatementExecutor(*procedural).handle_call(call);
1641					} else {
1642						require(subr, subr.subroutineKind == ast::SubroutineKind::Function);
1643						ProceduralContext context(netlist, ProcessTiming::implicit);
1644						StatementExecutor visitor(context);
1645						visitor.eval.ignore_ast_constants = ignore_ast_constants;
1646						ret = visitor.handle_call(call);
1647	
1648						RTLIL::Process *proc = netlist.canvas->addProcess(netlist.new_id());
1649						transfer_attrs(netlist, call, proc);
1650						context.copy_case_tree_into(proc->root_case);
1651					}
1652				}
1653			}
1654			break;
1655		case ast::ExpressionKind::LValueReference:
1656			ast_invariant(expr, lvalue != nullptr);
1657			ret = (*this)(*lvalue);
1658			break;
1659		default:
1660			netlist.add_diag(diag::LangFeatureUnsupported, expr.sourceRange);
1661			goto error;
1662		}
1663	
1664		if (0) {
1665	error:
1666		ret = RTLIL::SigSpec(RTLIL::Sx, (int) expr.type->getBitstreamWidth());
1667		}
1668	
1669	done:
1670		ast_invariant(expr, ret.size() == (int) expr.type->getBitstreamWidth());
1671		return ret;
1672	}
1673	
1674	RTLIL::SigSpec EvalContext::eval_signed(ast::Expression const &expr)
1675	{
1676		log_assert(expr.type);
1677	
1678		if (expr.type->isNumeric() && !expr.type->isSigned())
1679			return {RTLIL::S0, (*this)(expr)};
1680		else
1681			return (*this)(expr);
1682	}
