			canvas->uniquify(Yosys::stringf("%s$neg$q", base_name.c_str())), d.size());

	if (aload.is_fully_def() && aload.size() == 1 && aload.as_bool() != aload_polarity) {
		RTLIL::Cell *pos_ff =
				canvas->addDff(canvas->uniquify(Yosys::stringf("%s$pos", base_name.c_str())), clk,
