10	
11		always @* begin
12			if (^sel === 'x) begin
13				assert(o === 1'bx);
14			end else begin
15				if (little_endian) begin
16					if (sel > $signed(MSB) || sel < $signed(LSB)) begin
17						assert(o === 1'bx);
18					end else begin
19						assert(o === {data >> (sel - LSB)}[0]);
20					end
